function Education() {
  const educationServices = [
    {
      title: "Math Tutoring",
      image: "https://cdn-icons-png.flaticon.com/512/3135/3135755.png",
      description:
        "Get support with math lessons, exercises, and homework from community volunteers.",
      path: "/math-tutoring",
    },
    {

      title: "Chemistry Support",
      image:
        "https://cdn-icons-png.flaticon.com/512/2784/2784445.png",
      description:
        "Get help with chemistry lessons, equations, experiments, and homework support.",
      path: "/chemistry-support",
    },
    {
      title: "Programming Help",
      image: "https://cdn-icons-png.flaticon.com/512/2721/2721297.png",
      description:
        "Learn basic coding concepts, solve programming exercises, and improve your technical skills.",
      path: "/education",
    },
    {
      title: "Online Learning Support",
      image: "https://cdn-icons-png.flaticon.com/512/3976/3976626.png",
      description:
        "Receive help using online learning platforms, digital resources, and study tools.",
      path: "/education",
    },
  ];

  return (
    <section className="page-section">
      <div className="page-header">
        <h1>Education Help</h1>

        <p>
          Education Help connects students with community members who can support
          learning, homework, language practice, and digital study skills.
        </p>
      </div>

      <section className="cards">
        {educationServices.map((service, index) => (
          <div
            className="card"
            key={index}
            onClick={() => (window.location.href = service.path)}
          >
            <img
              src={service.image}
              alt={service.title}
              className="service-image"
            />

            <h3>{service.title}</h3>

            <p>{service.description}</p>
          </div>
        ))}
      </section>
    </section>
  );
}

export default Education;
